module RefModule(
    adder,
    address,
    rst,
    clk,
);input clk;
input rst;
input [15:0] adder;
output [7:0] address;
reg   [15:0] unused_count;
assign address[7:0] = unused_count[15:8];
always @(posedge clk or posedge rst) begin
    if (rst) begin
        unused_count <= 0;
    end
    else
    begin
        unused_count <= unused_count + adder;    
    end
end
endmodule
